// MARK: - Certificate Pinning Delegate

final class SecureSessionDelegate: NSObject, URLSessionDelegate, URLSessionTaskDelegate {
    
    // SHA-256 hashes of the public keys for api.example.com certificates
    // In production, replace these with your actual certificate pin hashes.
    private let pinnedPublicKeyHashes: [String: Set<String>] = [
        "api.example.com": [
            "AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA=",  // Primary pin
            "BBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBBB="   // Backup pin
        ]
    ]
    
    // Domains that are allowed to use insecure HTTP (legacy only)
    private let insecureAllowedHosts: Set<String> = [
        "legacy.internal"
    ]
    
    func urlSession(
        _ session: URLSession,
        didReceive challenge: URLAuthenticationChallenge,
        completionHandler: @escaping (URLSession.AuthChallengeDisposition, URLCredential?) -> Void
    ) {
        guard let serverTrust = challenge.protectionSpace.serverTrust,
              challenge.protectionSpace.authenticationMethod == NSURLAuthenticationMethodServerTrust else {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        let host = challenge.protectionSpace.host
        
        // For legacy.internal, we don't do certificate pinning (it's HTTP),
        // but we also don't blindly trust arbitrary certificates.
        if insecureAllowedHosts.contains(host) {
            completionHandler(.performDefaultHandling, nil)
            return
        }
        
        // For pinned domains, perform certificate public key pinning
        if let expectedHashes = pinnedPublicKeyHashes[host] {
            if evaluateTrust(serverTrust, against: expectedHashes, for: host) {
                let credential = URLCredential(trust: serverTrust)
                completionHandler(.useCredential, credential)
            } else {
                // Pin validation failed — reject the connection
                completionHandler(.cancelAuthenticationChallenge, nil)
            }
            return
        }
        
        // For all other domains, use default system validation (strict TLS)
        completionHandler(.performDefaultHandling, nil)
    }
    
    private func evaluateTrust(
        _ serverTrust: SecTrust,
        against expectedHashes: Set<String>,
        for host: String
    ) -> Bool {
        // Set SSL policy for the specific hostname
        let policy = SecPolicyCreateSSL(true, host as CFString)
        SecTrustSetPolicies(serverTrust, policy)
        
        // Evaluate the trust chain
        var error: CFError?
        guard SecTrustEvaluateWithError(serverTrust, &error) else {
            return false
        }
        
        // Check that at least one certificate in the chain matches a pinned hash
        let certificateCount = SecTrustGetCertificateCount(serverTrust)
        for index in 0..<certificateCount {
            guard let certificate = SecTrustCopyCertificateChain(serverTrust) as? [SecCertificate],
                  index < certificate.count else {
                continue
            }
            
            let cert = certificate[index]
            if let publicKey = SecCertificateCopyKey(cert),
               let publicKeyData = SecKeyCopyExternalRepresentation(publicKey, nil) as Data? {
                let hash = sha256Hash(of: publicKeyData)
                if expectedHashes.contains(hash) {
                    return true
                }
            }
        }
        
        return false
    }
    
    private func sha256Hash(of data: Data) -> String {
        var hash = [UInt8](repeating: 0, count: 32)
        data.withUnsafeBytes { buffer in
            guard let baseAddress = buffer.baseAddress else { return }
            CC_SHA256(baseAddress, CC_LONG(data.count), &hash)
        }
        return Data(hash).base64EncodedString()
    }
}

