// MARK: - Network Errors

enum NetworkError: LocalizedError {
    case disallowedHost(String)
    case insecureConnectionNotAllowed(String)
    case invalidResponse
    case httpError(Int)
    case noData
    
    var errorDescription: String? {
        switch self {
        case .disallowedHost(let host):
            return "Connection to host '\(host)' is not allowed by security policy."
        case .insecureConnectionNotAllowed(let host):
            return "Insecure HTTP connection to '\(host)' is not permitted. Use HTTPS."
        case .invalidResponse:
            return "Invalid server response."
        case .httpError(let code):
            return "HTTP error with status code \(code)."
        case .noData:
            return "No data received from server."
        }
    }
}

